			Date time) {
		IndexMessage im = SMsgFactory.getUMsg(tag, indexcode, time);
		im.setNeedAccessExtIndexDb(false);
		im.setNeedAccessCompanyBaseIndexDb(false);
		return IndexValueAgent.getIndexValue(im);
	}

}

