public class CacheUtilService {

	static Logger logger = LoggerFactory.getLogger(IndexService.class);
	static Set<String> timeset = new HashSet<String>();//初始时加载了哪些时间点的扩展表指标
	@SuppressWarnings("rawtypes")
	public static void loadAllCompanyOneExtIndexOfOneTag2cache(String tag ,String indexcode, Date time) {
		if(timeset.contains(DateUtil.formatYYYYMMDD2YYYYMM(time))) 
			return;
		doLoadAllCompanyOneExtIndexOfOneTag2cache(tag, indexcode, time);

	}
	@SuppressWarnings("rawtypes")
	private static void doLoadAllCompanyOneExtIndexOfOneTag2cache(String tag,
			String indexcode, Date time) {
		List<Map> l =IndexService.getInstance().getAllCompanyOneExtIndexOfOneTag2cache(tag ,indexcode,time);
		Dictionary d = DictService.getInstance().getDataDictionary(indexcode);
		if(l!=null&&l.size()>0)
		{
			for(Map m : l)
			{

				Extindex evo = new Extindex();
				evo.setCompanyCode(String.valueOf(m.get("COMPANY_CODE")));
				evo.setIndexCode(d.getIndexCode());
				evo.setTime(time);
				evo.setIndexName(d.getShowName());
				String cname = StockUtil.getExtCovertTableIndexCode(d.getIndexCode());

				Object v = m.get(cname);
				if(v==null)
				{
					//v = StockConstants.DEFAULT_DOUBLE_VALUE;
					continue;
				}
				evo.setValue(Float.valueOf(v.toString()));
//				ExtCacheService.getInstance().put(evo.getKey(),  evo.getValue());
				TUextService.getInstance().putData(evo.getCompanyCode(), evo.getTime().getTime(), evo.getIndexCode(), evo.getValue());
			}
		}

	}


	@SuppressWarnings("rawtypes")
