private static String DictArray2IndustryString(List<Dictionary> cl,String type) {
	if(cl==null|cl.size()==0) return null;
	StringBuffer sb = new StringBuffer();
	for(Dictionary d : cl)
	{
		String iindexcode = StockUtil.getIndustryCode(type, d.getIndexCode());
		sb.append("INDEX_CODE='"+iindexcode+"'");
		sb.append(" or ");
	}
	//去掉后面的“，”号
	return sb.substring(0, sb.length()-3);
}

