	@SuppressWarnings("rawtypes")
	public static void loadPreData2cache(String companycode,List<Dictionary> cl) {
		String indexlist = DictArray2String(cl);
		if(StringUtil.isEmpty(indexlist)) return;
		Date etime = StockUtil.getApproPeriod(new Date());
		Date stime = StockUtil.getNextTime(etime, -48);
		List<Map> l = IndexService.getInstance().getCompanyIndexDataFromMidTable(companycode,indexlist,stime,etime);
		if(l!=null&&l.size()>0)
		{
			for(Map m : l)
			{

				Extindex evo = new Extindex();
				evo.setCompanyCode(companycode);
				evo.setTime((Date) m.get("time"));
				for(Dictionary d : cl)
				{
					if(!StockUtil.isBaseIndex(d.getType()))
					{
						evo.setIndexCode(d.getIndexCode());
						evo.setIndexName(d.getShowName());
						String cname = StockUtil.getExtCovertTableIndexCode(d.getIndexCode());
						if(StockUtil.isBaseIndex(d.getType()))
						{
							cname = d.getColumnName();
						}
						Object v = m.get(cname);
						if(v==null)
						{
							continue;
						}
						evo.setValue(Float.valueOf(v.toString()));
//						ExtCacheService.getInstance().put(evo.getKey(),  evo.getValue());
						TUextService.getInstance().putData(evo.getCompanyCode(), evo.getTime().getTime(), evo.getIndexCode(), evo.getValue());
					}
				}

			}
		}
	}

