	private static void InitOneTimeCompanyExtIndex2Cache(String time) {

		int pageCount = getPageSize(time);
		for (int p = 0; p < pageCount; p++) {
			int start = p * pageSize;
			List<Map> l  = IndexService.getInstance().getCompanyIndexListOneTimeFromMidCompanyIndexExt(time,start,pageSize);

			if(l!=null&&l.size()>0)
			{
				for(Map m : l)
				{

					Extindex evo = new Extindex();
					evo.setCompanyCode(String.valueOf(m.get("COMPANY_CODE")));
//					if(evo.getCompanyCode().equals("000651.sz"))
//					{
//						System.out.println("测试代码:"+evo.getCompanyCode());
//					}
					List<Dictionary> dl = DictService.getInstance().getAllDictionaryListFromCache();
					for(Dictionary d : dl)
					{
						if(!StockUtil.isBaseIndex(d.getType())&&d.getType()>0)
						{
							evo.setIndexCode(d.getIndexCode());
							evo.setTime(DateUtil.format(time));
							evo.setIndexName(d.getShowName());
							String cname = StockUtil.getExtCovertTableIndexCode(d.getIndexCode());
							if(StockUtil.isBaseIndex(d.getType()))
							{
								cname = d.getColumnName();
							}
							Object v = m.get(cname);
							if(v==null)
							{
