							}
							evo.setValue(Float.valueOf(v.toString()));
//							ExtCacheService.getInstance().put(evo.getKey(),  evo.getValue());
							TUextService.getInstance().putData(evo.getCompanyCode(), evo.getTime().getTime(), evo.getIndexCode(), evo.getValue());
						}
					}

				}
