public class DataLoadTimeMng {

	private static DataLoadTimeMng instance = new DataLoadTimeMng();
	private DataLoadTimeMng() {
	}

	public static DataLoadTimeMng getInstance() {
		return instance;
	}
	private Map<String, Object> attrMap = new ConcurrentHashMap<String, Object>();

	public void putAttr(String k, Object v) {
		if (v != null)
			attrMap.put(k, v);
	}

	public <V> V getLoadTime(String k) {
		Object v = attrMap.get(k);
		if (v == null)
			return null;
		return (V) v;
	}


	private void putDataLoadTime(String k, Date v) {
		if (v != null)
		{
			Date lv = (Date) v;
			Date otime = getLoadTime(k);
			if(otime==null||lv.getTime()<otime.getTime())
				attrMap.put(k, v);

		}

	}

	private String getKey(String uidentify,Dictionary d)
	{
		return StockUtil.joinString("^", uidentify,d.getTimeUnit(),d.getTctype());
	}
	public void putDataLoadTime(String uidentify,Dictionary d, Date v) {
		if (v != null)
		{
			Date lv = (Date) v;
			String k = getKey(uidentify,d);
			Date otime = getLoadTime(k);
			if(otime==null)
			{
				Dictionary dd = DictService.getInstance().getDataDictionaryFromCache(StockConstants.INDEX_CODE_TRADE_S);
				String dayk = getKey(uidentify,dd);
				otime = getLoadTime(dayk);
				if(otime!=null)
					attrMap.put(k, otime);
			}
			if(otime==null||lv.getTime()<otime.getTime())
				attrMap.put(k, v);

		}

	}
	public void putDataLoadTime(String uidentify,String indexcode, Date v) {
		if (v != null)
		{
			Date lv = (Date) v;
			Dictionary d = DictService.getInstance().getDataDictionaryFromCache(indexcode);
			if(d==null)
				return;
			String k = getKey(uidentify,d);
			Date otime = getLoadTime(k);
			if(otime==null)
			{
				Dictionary dd = DictService.getInstance().getDataDictionaryFromCache(StockConstants.INDEX_CODE_TRADE_S);
				String dayk = getKey(uidentify,dd);
				otime = getLoadTime(dayk);
				if(otime!=null)
					attrMap.put(k, otime);
			}
			if(otime==null||lv.getTime()<otime.getTime())
				attrMap.put(k, v);

		}

	}
}

