public class IndexCacheLoadService extends PageCacheLoadService {

	public void addData2Cache(List<BaseVO> dlist) {

		if (dlist != null) {
			try {
				for (BaseVO vo : dlist) {
					// 去掉通用报表中的金融类公司
					ICompanyAttr av = (ICompanyAttr) vo;
					if(av.getCompanyCode().indexOf(".")<0) continue;
					Company c = CompanyService.getInstance().getCompanyByCodeFromCache(
							av.getCompanyCode());
					if(c==null) continue;
					if(vo instanceof Asset0290 ||vo instanceof Profile0291 ||vo instanceof Cash0292 )
					{
						if (!StringUtil.isEmpty(c.getTsc())
								&& !StockConstants.TS_00003.equals(c.getTsc()))
							continue;
					}

					String cacheName = getCacheName(vo.getDataType());
					lcEnter.put(vo.getKey(), vo, cacheName);
				}

			} catch (Exception e) {
				logger.error("addData2Cache failed!", e);
			}
		}
	}
}

