public class IndexCacheService {

	private static IndexCacheService instance = new IndexCacheService();
	static Map<String, String> mc = new HashMap<String, String>();
	LCEnter lcenter = LCEnter.getInstance();
	static {
		init();
		ConfigCenterFactory.notifyRefresh(new IConfigRefresh() {

			public void refresh() {
				init();
			}
		});
	}

	static void init() {
		String pt = ConfigCenterFactory
				.getString(
						"stock_zjs.tablename_datatype_peer",
						"t_finace0001:asset,t_finace0002:profile,t_finace0003:cash,t_finace0004:asset,t_finace0005:profile,t_finace0006:cash,t_finace0007:asset,t_finace0008:profile,t_finace0009:cash,t_finace0010:asset,t_finace0011:profile,t_finace0012:cash,v_trade0001:trade0001");
		for(String p:pt.split(","))
		{
			String[] pa = p.split(":");
			mc.put(pa[0],
					pa[1]);
		}

	}

	private IndexCacheService() {

	}

	public static IndexCacheService getInstance() {
		return instance;
	}

	public Object getValue(IndexMessage req) {
		String key = getIndexVoKey(req);
		String cacheName = getCacheName(req.getTableName(),key);
		Object o = lcenter.get(key, cacheName);
		if (o != null) {
			o = StockUtil.getFieldValueByColumnName(o, req.getColumnName());
			if(o!=null)
			{
				if(o instanceof Double)
				{
					Double ov = (Double) o;
					if(ov==0)
						return null;
				}
				if(o instanceof Float)
				{
					Float ov = (Float) o;
					if(ov==0)
						return null;
				}
			}
		}
		return o;
	}

	private String getIndexVoKey(IndexMessage req) {
		return StockUtil.getVoKey(req.getCompanyCode(), req.getTime());
	}

	/*
	 * time same as:1388678400000
	 */
	public String getIndexVoKey(String companycode,Long time) {
		return StockUtil.getVoKey(companycode, time);
	}

	public String getCacheName(String tableName,String key) {
		// TODO Auto-generated method stub
		String dtype = mc.get(tableName);
		return StockUtil.getBaseCacheName(dtype,key);
	}

	/**
	 * 现在类型是基础指标,并且可能变化的,只有行情类指标,所以此处默认行情对像
	 * @param uidentify
	 * @param time
	 * @param indexcode
	 */
	public void putBaseIndexValue2Cache(String uidentify, Long time,
			String indexcode,Object v) {
		String key = getIndexVoKey(uidentify,time);
		Dictionary d = DictService.getInstance().getDataDictionary(indexcode);
		String cacheName = getCacheName(d.getTableName(),key);
		Object o = lcenter.get(key, cacheName);
		if (o == null) {
			o = new Trade0001();
		}
		StockUtil.setValue2VO(o, v, d.getColumnName());
		lcenter.put(key, o, cacheName);
	}


	public void clearBaseIndexValue2Cache(String uidentify, Long time,
			String indexcode) {
		String key = getIndexVoKey(uidentify,time);
		Dictionary d = DictService.getInstance().getDataDictionary(indexcode);
		String cacheName = getCacheName(d.getTableName(),key);
		Object o = lcenter.get(key, cacheName);
		if (o != null) {
			StockUtil.setValue2VO(o, null, d.getColumnName());
			lcenter.put(key, o, cacheName);
		}

	}

}

