public class PageCacheLoadService extends BaseLoadService {

	public int pageSize = 5000;
	public int getPageSize(String dType) {
		int count = 0;
		RequestMessage req = DAFFactory.buildRequest(getCountSqlKey(dType),
				false, dType);
		ResponseMessage resp = dbOpt.queryForObject(req);
		if (resp.getRetrunCode().equals(BaseCodes.SUCCESS)) {
			count = (Integer) resp.getResult();
		}
		if(count==0) return 0;
		return count / pageSize + 1;

	}

	private String getCountSqlKey(String dType) {
		return "get" + dType + "AllCount";
	}


	public void doLoadData2Cache(String dType) {

		try {
			int pageCount = getPageSize(dType);
			for (int p = 0; p < pageCount; p++) {
				int start = p * pageSize;
				List<BaseVO> retList = loadDataFromDBByPage(dType, start,
						pageSize);
				addData2Cache(retList);
			}
		} catch (Exception e) {
			logger.error("load Asset data failed!", e);
		}

	}

	public List<BaseVO> loadDataFromDBByPage(String dType, int start, int limit) {
		Map<String, Object> m = new HashMap<String, Object>();
		m.put("start", start);
		m.put("limit", limit);
		List<BaseVO> retList = null;
		RequestMessage req = DAFFactory.buildRequest(getPageSqlKey(dType), m,
				dType);
		ResponseMessage resp = dbOpt.queryForList(req);
		if (resp.getRetrunCode().equals(BaseCodes.SUCCESS)) {
			retList = (List) resp.getResult();
		}
		return retList;

	}

	public String getPageSqlKey(String dType) {
		// TODO Auto-generated method stub
		return "get" + dType + "PageData2Cache";
	}

}

