//					mrl.add(ri);
//			}
//		}
//		if(mrl.size()==0) return null;
//		return computeRouter(mrl,r);
//	}

	/**
	 * 根据不同的需要，计算路由，此处先用哈希取余来计算
	 * 以后改为一致哈希
	 * @param mrl
	 * @param r
	 * @return
	 */
	private Dbrouter computeRouter(List<Dbrouter> mrl, DcssReqMsg r) {

		int i =  StockUtil.hashMod(r.getK().toString(),mrl.size());
		return mrl.get(i);
	}
